// Parse intent signal
const input = $input.first().json.body || $input.first().json;

const intentSignals = {
  high: ['pricing', 'demo', 'compare', 'discount', 'buy', 'purchase'],
  medium: ['features', 'integration', 'case study', 'how it works'],
  low: ['general question', 'careers', 'press']
};

const message = input.message || input.text || '';
const detectedIntent = intentSignals.high.find(s => message.toLowerCase().includes(s)) ? 'high' :
                       intentSignals.medium.find(s => message.toLowerCase().includes(s)) ? 'medium' : 'low';

return [{
  json: {
    signal_type: input.signal_type || 'chat',
    customer_id: input.customer_id,
    channel: input.channel || 'chat',
    message: message,
    detected_intent: detectedIntent,
    products_viewed: input.products_viewed || [],
    time_on_page: input.time_on_page || 0,
    timestamp: new Date().toISOString()
  }
}];

