// Process qualification
const aiResponse = $input.first().json.content;
const signal = $input.all()[0].json;
const customer = $input.all()[1]?.json?.[0] || {};

let qualification;
try {
  qualification = JSON.parse(aiResponse);
} catch (e) {
  qualification = {
    intent_level: signal.detected_intent,
    next_action: 'nurture',
    message: 'Thanks for your interest!',
    follow_up_delay: '3 days',
    priority: 'medium'
  };
}

// Determine follow-up sequence
const sequences = {
  high: { delay: 'immediate', next: '24h', then: '72h' },
  medium: { delay: 'immediate', next: '3 days', then: '7 days' },
  low: { delay: 'weekly', next: '7 days', then: '14 days' }
};

return [{
  json: {
    automation_id: 'SALE-' + Date.now(),
    customer_id: signal.customer_id,
    customer_email: customer.email,
    customer_phone: customer.phone,
    intent_level: qualification.intent_level,
    signal_type: signal.signal_type,
    next_action: qualification.next_action,
    message: qualification.message,
    follow_up_sequence: sequences[qualification.intent_level],
    priority: qualification.priority,
    calendly_booked: qualification.intent_level === 'high',
    follow_up_scheduled: new Date(Date.now() + 86400000).toISOString(),
    timestamp: signal.timestamp
  }
}];

